#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <streambuf> // For std::streambuf

// Forward declaration of the function containing the student's logic
// This function must be defined in the student's submitted code.
void run_multiplication_table_logic();

// This function captures stdout when run_multiplication_table_logic is called
// and allows feeding input to stdin.
std::string capture_output(const std::string& input) {
    std::stringstream ss_input(input);
    std::stringstream ss_output;

    // Save original streambufs
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    // Redirect cin and cout
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    // Call the student's main logic function
    run_multiplication_table_logic();

    // Restore original streambufs
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return ss_output.str();
}
